  "stud-notch-bore-limit": {
    formula: "notch_max_bearing = 0.25 x stud_width; notch_max_nonbearing = 0.40 x stud_width; bore_single_max = 0.40 x stud_width; bore_doubled_max = 0.60 x stud_width; edge_min = 0.625 in (5/8 in).",
    edition: "IRC R602.6 wall-stud notching and boring limits, by name; the percentages apply to the actual stud width. The AHJ-adopted IRC edition governs.",
    freeAccess: "The percentage limits are prescriptive IRC R602.6 values (many jurisdictions post the adopted IRC); the tile applies them to the entered actual stud width.",
    governance: GOVERNANCE.general,
    editionNote: "IRC R602.6 limits on notching and boring wall studs, applied to the ACTUAL stud width (a 2x4 is 3.5 in, a 2x6 is 5.5 in). A notch may not exceed 25% of the width in a bearing or exterior wall, or 40% in a nonbearing wall. A bored hole may not exceed 40% of the width in a single stud, or 60% if the stud is doubled (and no more than two successive doubled studs are bored to 60%). The edge of the hole must be at least 5/8 in from the edge of the stud, and a bored hole may not be located in the same cross section as a cut or notch. These are the prescriptive limits for conventional light-frame construction; a designated plumbing or mechanical wall, an engineered stud, a tall wall, or a braced/shear wall may be more restrictive, and the AHJ-adopted code and any engineering govern.",
    assumptions: [
      { name: "Actual width", value: "percentages apply to the actual dressed width (2x4 = 3.5 in, 2x6 = 5.5 in), not the nominal", source: "IRC R602.6" },
      { name: "Doubled stud / edge", value: "bore up to 60% only on a doubled stud (<=2 successive); hole edge >= 5/8 in; not in the same section as a notch", source: "IRC R602.6" },
    ],
  },
  "joist-notch-bore-limit": {
    formula: "end_notch_max = D/4; notch_depth_max = D/6; notch_length_max = D/3; bore_dia_max = D/3; bore_edge_min = 2 in (D = actual joist depth).",
    edition: "IRC R502.8.1 sawn-lumber floor-joist notching and boring limits, by name; the fractions apply to the actual joist depth. The AHJ-adopted IRC edition governs.",
    freeAccess: "The fractional limits are prescriptive IRC R502.8.1 values (many jurisdictions post the adopted IRC); the tile applies them to the entered actual joist depth.",
    governance: GOVERNANCE.general,
    editionNote: "IRC R502.8.1 limits on notching and boring SAWN-LUMBER floor joists, applied to the ACTUAL joist depth (a 2x10 is 9.25 in, a 2x12 is 11.25 in). A notch at the bearing ends may not exceed one quarter of the depth (D/4). A notch elsewhere on the top or bottom edge is limited to D/6 in depth and D/3 in length, and notches are NOT permitted in the middle third of the span. A bored hole may not exceed D/3 in diameter, and its edge must be at least 2 in from the top and bottom edges of the joist and at least 2 in from any other hole or notch. These prescriptive limits are for dimension lumber ONLY -- engineered I-joists, LVL, and trusses follow the manufacturer's hole chart and web-stiffener rules, and a flange must never be field-notched. A cantilever, a doubled/built-up member, or a heavily loaded joist may be more restrictive, and the AHJ-adopted code and any engineering govern.",
    assumptions: [
      { name: "Actual depth", value: "fractions apply to the actual dressed depth (2x10 = 9.25 in, 2x12 = 11.25 in), not the nominal", source: "IRC R502.8.1" },
      { name: "Sawn lumber only", value: "engineered I-joists / LVL / trusses follow the maker's hole chart; never notch a flange", source: "IRC R502.8.1 / manufacturer" },
    ],
  },
  "joist-cantilever-check": {
    formula: "cantilever_max_ft = backspan_ft / 4; within_limit when overhang_ft <= cantilever_max_ft; margin_ft = cantilever_max_ft - overhang_ft.",
    edition: "IRC R507.6 (decks) and R502.3.3 (floors) joist-cantilever provisions, by name; the 1:4 backspan ratio. The AHJ-adopted IRC edition governs.",
    freeAccess: "The 1:4 cantilever ratio is a prescriptive IRC value (many jurisdictions post the adopted IRC); the tile applies it to the entered backspan and overhang.",
    governance: GOVERNANCE.general,
    editionNote: "The prescriptive joist-cantilever ratio: a joist may overhang its support by no more than one quarter of its backspan (the span from that support back to the next support), per IRC R507.6 for decks and R502.3.3 for floors. So the maximum cantilever = backspan / 4, and the overhang must not exceed it. Beyond this ratio the prescriptive tables also set an absolute overhang cap and require the cantilever to be checked for uplift at the backspan support and for the load it carries. A joist cantilever that supports a beam, a wall, or a roof at its tip is NOT a prescriptive case -- it is an engineered condition. This is the ratio screen; the prescriptive span tables, the tip load, the connection at the backspan support (uplift), and the AHJ-adopted code govern.",
    assumptions: [
      { name: "1:4 ratio", value: "max cantilever = backspan / 4; the prescriptive tables also cap the absolute overhang", source: "IRC R507.6 / R502.3.3" },
      { name: "Tip load is engineered", value: "a beam / wall / roof bearing on the cantilever tip is an engineered condition, not prescriptive", source: "IRC / engineering" },
    ],
  },
